"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[8615],{423:e=>{e.exports=JSON.parse('{"functions":[{"name":"Filter","desc":"Callback invoked for each raycast hit. Return `true` to allow the bullet\\nto bounce off the surface.\\n\\nMust be **synchronous** \u2014 yielding inside this callback terminates the cast\\nwith an error on the next frame.\\n\\nSignature: `(context: BulletContext, result: RaycastResult, velocity: Vector3) -> boolean`\\n\\nDefault: `nil` (no bouncing)","params":[{"name":"callback","desc":"","lua_type":"(context: BulletContext, result: RaycastResult, velocity: Vector3) -> boolean"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":350,"path":"docs/SubBuilders.lua"}},{"name":"Max","desc":"Maximum total bounces across the bullet\'s entire lifetime.\\n\\nDefault: `5`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":360,"path":"docs/SubBuilders.lua"}},{"name":"SpeedThreshold","desc":"Minimum speed in studs per second required for a bounce attempt.\\nBelow this speed the hit is treated as a terminal impact.\\n\\nDefault: `20`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":371,"path":"docs/SubBuilders.lua"}},{"name":"Restitution","desc":"Energy-retention coefficient applied to reflected velocity. Must be in `[0, 1]`.\\n`1.0` = perfectly elastic (no energy loss). `0.0` = bullet stops on first contact.\\n\\nCombined multiplicatively with `MaterialRestitution` for the hit surface\'s\\nmaterial. The `SubsonicProfile.Restitution` override applies when the bullet\\nis subsonic.\\n\\nDefault: `0.7`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":386,"path":"docs/SubBuilders.lua"}},{"name":"MaterialRestitution","desc":"Per-material restitution multipliers, keyed by `Enum.Material`.\\nCombined multiplicatively with the base [BounceBuilder:Restitution].\\nOmitted materials use a multiplier of `1.0`.\\n\\n```lua\\n:MaterialRestitution({\\n    [Enum.Material.Concrete] = 0.5,\\n    [Enum.Material.Plastic]  = 0.95,\\n})\\n```\\n\\nDefault: `{}`","params":[{"name":"value","desc":"","lua_type":"{[Enum.Material]: number}"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":405,"path":"docs/SubBuilders.lua"}},{"name":"NormalPerturbation","desc":"Adds random noise to the surface normal before reflecting, simulating rough\\nor irregular surfaces. `0` = clean mirror reflection. Higher values scatter\\nthe bullet more unpredictably. The `SubsonicProfile.NormalPerturbation`\\noverride applies when the bullet is subsonic.\\n\\nDefault: `0.0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":418,"path":"docs/SubBuilders.lua"}},{"name":"ResetPierceOnBounce","desc":"When `true`, pierce state (`PiercedInstances`, `PierceCount`, and the\\n`FilterDescendantsInstances` filter) is automatically reset after each\\nconfirmed bounce, restoring the full pierce budget for the new arc.\\n\\nRequired for bounce + pierce combinations where the post-bounce trajectory\\nshould be able to re-detect previously pierced surfaces.\\n\\nFor conditional resets (e.g. only after the first bounce), call\\n`cast:ResetPierceState()` manually inside an `OnBounce` handler instead.\\n\\nDefault: `false`","params":[{"name":"value","desc":"","lua_type":"boolean"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":436,"path":"docs/SubBuilders.lua"}},{"name":"Done","desc":"Returns the root [BehaviorBuilder].","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"method","source":{"line":443,"path":"docs/SubBuilders.lua"}}],"properties":[],"types":[],"name":"BounceBuilder","desc":"Sub-builder for bounce configuration. Opened via [BehaviorBuilder:Bounce].\\nCall `:Done()` to return to the root [BehaviorBuilder].\\n\\n:::caution\\nPierce and bounce are mutually exclusive per hit. Bounce is only evaluated\\nif pierce did not occur on that hit.\\n:::","source":{"line":334,"path":"docs/SubBuilders.lua"}}')}}]);